public void testBinaryAsEmbeddedObjectEmpty() throws Exception
{
    JsonGenerator g;

    StringWriter sw = new StringWriter();
    g = JSON_F.createGenerator(sw);
    g.writeEmbeddedObject(new byte[0]);
    g.close();
    assertEquals("\"\"", sw.toString());

    ByteArrayOutputStream bytes = new ByteArrayOutputStream(100);
    g = JSON_F.createGenerator(bytes);
    g.writeEmbeddedObject(new byte[0]);
    g.close();
    assertEquals("\"\"", bytes.toString("UTF-8"));
}

public void testAsEmbeddedInArray() throws Exception
{
    JsonGenerator g;

    StringWriter sw = new StringWriter();
    g = JSON_F.createGenerator(sw);
    g.writeStartArray();
    g.writeEmbeddedObject(null);
    g.writeEmbeddedObject(new byte[]{1, 2, 3});
    g.writeEndArray();
    g.close();
    String result = sw.toString();
    assertTrue(result.startsWith("[null,\""));
    assertTrue(result.endsWith("\"]"));
}
